import{_ as a,o as e,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"BDI 波羅的海乾散貨指數","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-2_BDI_波羅的海指數.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-2_BDI_波羅的海指數.md"}'),l={name:"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-2_BDI_波羅的海指數.md"};function d(o,t,n,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="bdi-波羅的海乾散貨指數" tabindex="-1">BDI 波羅的海乾散貨指數 <a class="header-anchor" href="#bdi-波羅的海乾散貨指數" aria-label="Permalink to &quot;BDI 波羅的海乾散貨指數&quot;">​</a></h1><h2 id="📊-指數構成與權重" tabindex="-1">📊 指數構成與權重 <a class="header-anchor" href="#📊-指數構成與權重" aria-label="Permalink to &quot;📊 指數構成與權重&quot;">​</a></h2><p>BDI（Baltic Dry Index）由波羅的海國際航交所（Baltic Exchange）每週一發布，反映乾散貨船運價總體水準。</p><h3 id="組成指數-2018-年-3-月起-handysize-移除" tabindex="-1">組成指數（2018 年 3 月起 Handysize 移除） <a class="header-anchor" href="#組成指數-2018-年-3-月起-handysize-移除" aria-label="Permalink to &quot;組成指數（2018 年 3 月起 Handysize 移除）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>組成部分</th><th>權重</th><th>船型</th><th>主要貨物</th></tr></thead><tbody><tr><td><strong>BCI</strong>（Capesize 指數）</td><td>40%</td><td>好望角型（15–18 萬 DWT）</td><td>鐵礦砂、煤炭</td></tr><tr><td><strong>BPI</strong>（Panamax 指數）</td><td>30%</td><td>巴拿馬型（6–8 萬 DWT）</td><td>穀物、煤炭、鋁土礦</td></tr><tr><td><strong>BSI</strong>（Supramax 指數）</td><td>30%</td><td>超靈便型（5–6 萬 DWT）</td><td>農產品、鋼材、水泥</td></tr></tbody></table><h3 id="最新數據-2026-5-12" tabindex="-1">最新數據（2026/5/12） <a class="header-anchor" href="#最新數據-2026-5-12" aria-label="Permalink to &quot;最新數據（2026/5/12）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指數</th><th>數值</th><th>備註</th></tr></thead><tbody><tr><td><strong>BDI</strong></td><td>3,063 點</td><td>2026 年 5 月 12 日，創 5 個月新高</td></tr><tr><td><strong>BCI</strong></td><td>5,082 點</td><td>創 5 年同月新高，受巴西鐵礦出口中斷支撐</td></tr><tr><td><strong>BPI</strong></td><td>2,360 點</td><td>穀物出口需求強勁</td></tr><tr><td><strong>BSI</strong></td><td>1,535 點</td><td>農產品貿易穩定</td></tr></tbody></table><hr><h2 id="📈-歷史走勢-2023–2026" tabindex="-1">📈 歷史走勢（2023–2026） <a class="header-anchor" href="#📈-歷史走勢-2023–2026" aria-label="Permalink to &quot;📈 歷史走勢（2023–2026）&quot;">​</a></h2><h3 id="_2023-年" tabindex="-1">2023 年 <a class="header-anchor" href="#_2023-年" aria-label="Permalink to &quot;2023 年&quot;">​</a></h3><ul><li>BDI 全年波動區間約 600–1,800 點</li><li>年初受中國房地產放緩影響，鐵礦需求疲弱</li><li>Q3 因澳洲煤炭出口回升有所反彈</li></ul><h3 id="_2024-年" tabindex="-1">2024 年 <a class="header-anchor" href="#_2024-年" aria-label="Permalink to &quot;2024 年&quot;">​</a></h3><ul><li>Q1–Q3 表現強勁，BDI 同比漲 41%，BCI 同比漲 94%</li><li>6–7 月創阶段性高點後，9 月因巴西鐵礦出貨放緩回落</li><li>11 月回升至 2,000 點以上（同比仍跌 10%）</li></ul><h3 id="_2025-年" tabindex="-1">2025 年 <a class="header-anchor" href="#_2025-年" aria-label="Permalink to &quot;2025 年&quot;">​</a></h3><ul><li>全年均價約 1,755 點，11 月達 2,104 點</li><li>亞洲基礎建設需求 + EV 電池礦產出口推動散裝貿易</li></ul><h3 id="_2026-年-當前" tabindex="-1">2026 年（當前） <a class="header-anchor" href="#_2026-年-當前" aria-label="Permalink to &quot;2026 年（當前）&quot;">​</a></h3><ul><li>1–2 月突破 2,000 點，受噸海里需求強勁支撐</li><li>5/7 達 3,034 點，創 2023 年 12 月以來最高</li><li>5/12 達 3,063 點，BCI 創 5 年同月新高（5,082）</li><li>5/13 續升至 3,189 點</li></ul><hr><h2 id="🔍-關鍵驅動因素-2026" tabindex="-1">🔍 關鍵驅動因素（2026） <a class="header-anchor" href="#🔍-關鍵驅動因素-2026" aria-label="Permalink to &quot;🔍 關鍵驅動因素（2026）&quot;">​</a></h2><h3 id="利多因素" tabindex="-1">利多因素 <a class="header-anchor" href="#利多因素" aria-label="Permalink to &quot;利多因素&quot;">​</a></h3><ol><li><strong>Simandou 鐵礦項目</strong>：幾內亞 Simandou 鐵礦開採量增加，長距離運輸需求推升 Capesize 航程</li><li><strong>澳洲/巴西出口強勁</strong>：鐵礦砂、煤炭出口持續增長，BDI 受益</li><li><strong>巴拿馬運河限制</strong>：乾旱導致通行量受限，部分貨物改走好望角</li><li><strong>EEXI/CII 降速</strong>：環保法規迫使老船降速，有效運力減少</li></ol><h3 id="風險因素" tabindex="-1">風險因素 <a class="header-anchor" href="#風險因素" aria-label="Permalink to &quot;風險因素&quot;">​</a></h3><ol><li><strong>新船交付壓力</strong>：散裝船隊訂單占活躍船隊約 20%，2026 年大量新船交付可能壓低運價</li><li><strong>中國需求放緩</strong>：房地產持續低迷，鐵礦進口增速可能放緩</li><li><strong>地緣政治溢價</strong>：中東衝突推升運價波動，但非結構性利多</li></ol><hr><h2 id="📊-capesize-租金水準-2026-5" tabindex="-1">📊 Capesize 租金水準（2026/5） <a class="header-anchor" href="#📊-capesize-租金水準-2026-5" aria-label="Permalink to &quot;📊 Capesize 租金水準（2026/5）&quot;">​</a></h2><ul><li><strong>即期航次租金</strong>：約 $28,000/天（2 月均價）</li><li><strong>1 年期期租</strong>：約 $30,000–$32,000/天</li><li><strong>損益平衡日租金</strong>：約 $8,500–$10,000/天（含營運成本 ~$6,094/天 + 資本成本）</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>Baltic Exchange (2026-05-12): BDI 3,063 / BCI 5,082 / BPI 2,360 / BSI 1,535</li><li>TradingEconomics (2026-05): BDI 歷史走勢與預測</li><li>Gerdau Market Update (2026-05): 鐵礦出口與散裝需求分析</li><li>Breakwave Advisors (2026-03-16): 散裝市場 2026 年展望</li><li>Seeking Alpha (2026-05): Pangaea Logistics Q1 2026 TCE 數據</li></ol>',29)])])}const g=a(l,[["render",d]]);export{_ as __pageData,g as default};
